import (
	"context"
	"fmt"

	"github.com/uptrace/bun"
	"github.com/uptrace/bun/migrate"

	"github.com/AlexL70/linkshortener/backend/business-logic/models"
)

// Migrations is the global migration registry for the application.
var Migrations = migrate.NewMigrations()

func init() {
	// 001 — initial schema
	Migrations.MustRegister(
		func(ctx context.Context, db *bun.DB) error {
			return createInitialSchema(ctx, db)
		},
		func(ctx context.Context, db *bun.DB) error {
			return dropInitialSchema(ctx, db)
		},
	)
}

// RunMigrations applies all pending up-migrations and returns the number applied.
func RunMigrations(ctx context.Context, db *bun.DB) error {
	migrator := migrate.NewMigrator(db, Migrations)

	if err := migrator.Init(ctx); err != nil {
		return fmt.Errorf("migration init: %w", err)
	}

	group, err := migrator.Migrate(ctx)
	if err != nil {
		return fmt.Errorf("migration run: %w", err)
	}

	if group.IsZero() {
		fmt.Println("migrations: no new migrations to apply")
	} else {
		fmt.Printf("migrations: applied migration group #%d (%d migrations)\n",
			group.ID, len(group.Migrations))
	}

	return nil
}

// createInitialSchema creates the full initial database schema.
func createInitialSchema(ctx context.Context, db *bun.DB) error {
	models := []interface{}{
		(*models.User)(nil),
		(*models.UserProvider)(nil),
		(*models.ShortenedURL)(nil),
		(*models.URLClick)(nil),
	}

	for _, model := range models {
		if _, err := db.NewCreateTable().Model(model).IfNotExists().Exec(ctx); err != nil {
			return err
		}
	}

	// Unique constraint on (provider, provider_user_id)
	_, err := db.ExecContext(ctx, `
		ALTER TABLE user_providers
		  ADD CONSTRAINT IF NOT EXISTS uq_user_providers_provider_uid
		  UNIQUE (provider, provider_user_id)
	`)
	if err != nil {
		return err
	}

	// Indexes for redirect hotpath and user lookups
	indexes := []string{
		`CREATE INDEX IF NOT EXISTS idx_user_providers_user_id    ON user_providers  (user_id)`,
		`CREATE UNIQUE INDEX IF NOT EXISTS idx_shortened_urls_shortcode ON shortened_urls (shortcode)`,
		`CREATE INDEX IF NOT EXISTS idx_shortened_urls_user_id    ON shortened_urls  (user_id)`,
		`CREATE INDEX IF NOT EXISTS idx_url_clicks_url_id         ON url_clicks      (url_id)`,
		`CREATE INDEX IF NOT EXISTS idx_url_clicks_clicked_at     ON url_clicks      (clicked_at)`,
		`CREATE INDEX IF NOT EXISTS idx_url_clicks_ip_address     ON url_clicks      (ip_address)`,
	}

	for _, idx := range indexes {
		if _, err := db.ExecContext(ctx, idx); err != nil {
			return err
		}
	}

	return nil
}

// dropInitialSchema reverses createInitialSchema (used in down-migration / tests).
func dropInitialSchema(ctx context.Context, db *bun.DB) error {
	tables := []string{"url_clicks", "shortened_urls", "user_providers", "users"}
	for _, t := range tables {
		if _, err := db.ExecContext(ctx, "DROP TABLE IF EXISTS "+t+" CASCADE"); err != nil {
			return err
		}
	}
	return nil
}

